1	/*
2	LayerNorm CUDA kernel, and also Residual, because sometimes they are fused
3	
4	Note in llm.c we try to be clever in the backward pass to conserve memory.
5	All parameters use a += in the backward pass, so we can do gradient accumulation.
6	But all activations have = instead of += because these are faster (just read, no write).
7	This is okay for all activations except for those in the residual stream, where the
8	gradients have to add. We make sure that we do a += as necessary.
9	E.g., the layernorms are connected to the residuals so we += in layernorm backward.
10	*/
11	
12	#include <assert.h>
13	// llmc internal imports
14	#include "cuda_common.h"
15	#include "cuda_utils.cuh"
16	
17	// ----------------------------------------------------------------------------
18	// CUDA kernels
19	
20	__global__ void layernorm_forward_kernel3(floatX* __restrict__ out, float* __restrict__ mean, float* __restrict__ rstd,
21	                                    const floatX*  __restrict__ inp, const floatX*  __restrict__ weight,
22	                                    const floatX* __restrict__ bias, int N, int C) {
23	    int lane_id = threadIdx.x % WARP_SIZE;
24	    int warp_id = threadIdx.x / WARP_SIZE;
25	    int num_warps = blockDim.x / WARP_SIZE;
26	
27	    int idx = blockIdx.x * num_warps + warp_id;
28	    if(idx >= N) { return; } // guard
29	
30	    // the row of input that this group of threads is responsible for
31	    const floatX* x = inp + idx * C;
32	
33	    // mean
34	    float sum = 0.0f;
35	    for (int i = lane_id; i < C; i += WARP_SIZE) {
36	        sum += (float)x[i];
37	    }
38	    sum = warpReduceSum(sum);
39	    float m = sum / C;
40	    if(lane_id == 0 && mean != nullptr) {
41	        __stcs(mean + idx, m);
42	    }
43	
44	    // rstd
45	    sum = 0.0f;
46	    for (int i = lane_id; i < C; i += WARP_SIZE) {
47	        float diff = (float)x[i] - m;
48	        sum += diff * diff;
49	    }
50	    sum = warpReduceSum(sum);
51	    float s = rsqrtf(sum / C + 1e-5f);
52	    if(lane_id == 0 && rstd != nullptr) {
53	        __stcs(rstd + idx, s);
54	    }
55	
56	    // final normalization and scaling by weight/bias
57	    floatX* o = out + idx * C;
58	    for (int c = lane_id; c < C; c += WARP_SIZE) {
59	        // load and store using the .cs "streaming" hint to the compiler,
60	        // indicating that this data will not be reused soon, and can be streamed through the caches
61	        // this allows the threads to get more cache-hits for the (shared) weight and bias parameters
62	        float n = s * ((float)__ldcs(x+c) - m);
63	        __stcs(o+c, (floatX)(n * (float)weight[c] + (float)bias[c]));
64	    }
65	}
