142	__global__ void fused_residual_forward_kernel5(floatX* residual, floatX* normed, float* mean, float* rstd,
143	                                               const floatX* inp1, const floatX* inp2,
144	                                               const floatX* weight, const floatX* bias,
145	                                               int N, int C) {
146	    assert(blockDim.x == WARP_SIZE);
147	
148	    // load weights and biases into shared memory
149	    // do this before we allow any threads to exit!
150	    extern __shared__ char* params[];
151	    // load128/store128 sometimes generated multiple instructions when the types here were floatX*, so
152	    // let's keep everything as x128
153	    x128* s_weight = reinterpret_cast<x128*>(params);
154	    x128* s_bias = reinterpret_cast<x128*>(params) + (C / x128::size);
155	    x128* s_res = reinterpret_cast<x128*>(params) + ((2 + threadIdx.y) * C / x128::size);
156	
157	    int sidx = (threadIdx.x + WARP_SIZE * threadIdx.y) * x128::size;
158	    for(int i = sidx; i < C; i += blockDim.y * WARP_SIZE * x128::size) {
159	        s_weight[i/x128::size] = load128(weight + i);
160	        s_bias[i/x128::size] = load128(bias + i);
161	    }
162	    __syncthreads();
163	
164	    int idx = blockIdx.x * blockDim.y + threadIdx.y;
165	    if(idx > N) return;
166	
167	    // adjust pointers to current token
168	    residual += C * idx;
169	    normed += C * idx;
170	    inp1 += C * idx;
171	    inp2 += C * idx;
172	
173	    const float eps = 1e-5f;
174	    float sum = 0.0f;
175	    for(int c = threadIdx.x * x128::size; c < C; c += WARP_SIZE * x128::size) {
176	        const x128 in1 = load128cs(inp1 + c);
177	        const x128 in2 = load128cs(inp2 + c);
178	        x128 out;
179	        for(int k = 0; k < x128::size; ++k) {
180	            out[k] = (float)in1[k] + (float)in2[k];
181	            sum += (float)out[k];
182	        }
183	        store128cs(residual + c, out);
184	        s_res[c / x128::size] = out;
185	    }
186	
187	    sum = warpReduceSum(sum);
188	    float m = sum / C;
189	    float v = 0.f;
190	
191	    for(int c = threadIdx.x * x128::size; c < C; c += WARP_SIZE * x128::size) {
192	        const x128 res = s_res[c / x128::size];
193	        for(int k = 0; k < x128::size; ++k) {
194	            v += ((float)res[k] - m) * ((float)res[k] - m);
195	        }
196	    }
197	
198	    v = warpReduceSum(v) / C;
199	    float s = rsqrtf(v + eps);
200	
201	    for(int c = threadIdx.x * x128::size; c < C; c += WARP_SIZE * x128::size) {
202	        const x128 res = s_res[c / x128::size];
203	        const x128 w = s_weight[c / x128::size];
204	        const x128 b = s_bias[c / x128::size];
205	        x128 out;
206	        for(int k = 0; k < x128::size; ++k) {
207	            float n = s * ((float)res[k] - m); // normalized output
208	            float o = n * (float)w[k] + (float)b[k]; // scale and shift it
209	            out[k] = o;
210	        }
211	
212	        store128cs(normed + c, out);
213	    }
214	    // cache the mean and rstd for the backward pass later
215	    if(threadIdx.x == 0) {
216	        mean[idx] = m;
217	        rstd[idx] = s;
218	    }
219	}
220	
221	__global__ void residual_forward_kernel(floatX* out, const floatX* inp1, const floatX* inp2) {
222	    int idx = (blockIdx.x * blockDim.x + threadIdx.x) * x128::size;
223	
224	    x128 packed_out;
225	    x128 packed_inp1 = load128cs(inp1 + idx);
226	    x128 packed_inp2 = load128cs(inp2 + idx);
227	    for (int k = 0; k < packed_inp1.size; k++) {
228	        packed_out[k] = (floatX)((float)packed_inp1[k] + (float)packed_inp2[k]);
229	    }
230	    store128(out + idx, packed_out);
231	}
