492	void layernorm_backward(floatX* dinp, floatX* dweight, floatX* dbias, float* scratch,
493	                        const floatX* dout, const floatX* inp, const floatX* weight, const float* mean, const float* rstd,
494	                        int B, int T, int C, cudaStream_t stream) {
495	    NVTX_RANGE_FN();
496	    const int block_size = 512;
497	    const int blocks_per_sm = 2; // supported on every architecture and less cache thrashing than 3
498	    const int grid_size = blocks_per_sm * deviceProp.multiProcessorCount;
499	    size_t rounded_C = CEIL_DIV(C, (32 * x128::size)) * (32 * x128::size);
500	    size_t shared_mem_size = (2 * rounded_C + 2 * (block_size - 32) * f128::size) * sizeof(float);
501	
502	    cudaCheck(cudaMemsetAsync(scratch, 0, 1 * sizeof(float), stream)); // only need to reset the flag to 0
503	    layernorm_backward_kernel10<<<grid_size, block_size, shared_mem_size, stream>>>(dinp, dweight, dbias, scratch, dout, inp, weight, mean, rstd, B, T, C);
504	    cudaCheck(cudaGetLastError());
505	}
