219:void fill_in_activation_sizes(const ActivationTensors* data, TensorSpec (&tensors)[NUM_ACTIVATION_TENSORS], size_t B, size_t T, GPT2Config config, int recompute) {
225:    // if recompute >= 1 then we will recompute the layernorm forward activation during backward pass
226:    tensors[1] = TENSOR_SPEC(data->ln1,  (recompute < 2) ? L * B * T * C : 0);
237:    // if recompute >= 1 then we will recompute the layernorm forward activation during backward pass
